from autogen import AssistantAgent, UserProxyAgent
import time

def latency_detector(conversation_history):
    metrics = []
    for msg in conversation_history[-10:]:
        if 'content' in msg and msg['role'] != 'user':
            token_count = len(msg['content'].split())
            response_time = msg.get('timestamp', time.time()) - msg.get('prev_timestamp', 0)
            if token_count > 1500 or response_time > 30:
                metrics.append({
                    'agent': msg.get('agent_name'),
                    'tokens': token_count,
                    'latency': response_time,
                    'warning': 'High latency detected'
                })
    return {'alert': len(metrics) > 2, 'metrics': metrics}

def profile_agent_latency(agent):
    start_times = {}
    def latency_wrapper(func):
        def wrapper(*args, **kwargs):
            agent_name = agent.name
            start_times[agent_name] = time.time()
            result = func(*args, **kwargs)
            latency = time.time() - start_times[agent_name]
            if latency > 20:
                print(f'⚠️ {agent_name} latency: {latency:.1f}s')
            return result
        return wrapper
    return latency_wrapper

class LatencyTracker:
    def __init__(self, max_latency=120):
        self.start_time = time.time()
        self.max_latency = max_latency
        self.turn_count = 0

    def on_new_turn(self):
        self.turn_count += 1
        total_latency = time.time() - self.start_time
        avg_latency = total_latency / self.turn_count
        if total_latency > self.max_latency:
            return {
                'alert': True,
                'total_latency': total_latency,
                'avg_per_turn': avg_latency,
                'recommendation': 'Implement token limits'
            }
        return {'alert': False}

